// Progressively enhances a plain, crawlable <ul class="chip-list"> of real
// <a href> category links into a compact searchable dropdown. The links
// themselves are never generated by this script — it only repositions the
// exact anchor tags already present in the server-rendered HTML, so nothing
// here can hide content from search engines: view-source / curl / a crawler
// with JS disabled all see the full, working link list either way.
(function () {
    document.querySelectorAll('[data-category-select]').forEach(function (container) {
        var list = container.querySelector('.chip-list');
        if (!list) return;

        var items = Array.prototype.slice.call(list.querySelectorAll('li'));
        var activeLink = list.querySelector('.chip-active');
        var allLabel = container.dataset.allLabel || 'All';

        var control = document.createElement('div');
        control.className = 'category-select-control';

        var trigger = document.createElement('button');
        trigger.type = 'button';
        trigger.className = 'category-select-trigger';
        trigger.setAttribute('aria-haspopup', 'listbox');
        trigger.setAttribute('aria-expanded', 'false');
        trigger.innerHTML = '<span>' + escapeHtml(activeLink ? activeLink.textContent.trim() : allLabel) + '</span><span class="category-select-caret" aria-hidden="true">&#9662;</span>';

        var panel = document.createElement('div');
        panel.className = 'category-select-panel';
        panel.hidden = true;

        var search = document.createElement('input');
        search.type = 'text';
        search.className = 'category-select-search';
        search.placeholder = container.dataset.searchPlaceholder || '';
        search.setAttribute('aria-label', search.placeholder);

        // Insert the control before the list, then move the real list
        // (same DOM nodes, same hrefs) into the panel.
        list.parentNode.insertBefore(control, list);
        panel.appendChild(search);
        panel.appendChild(list);
        control.appendChild(trigger);
        control.appendChild(panel);
        list.classList.add('category-select-list');

        function escapeHtml(s) {
            return String(s).replace(/[&<>"']/g, function (c) {
                return { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c];
            });
        }

        function open() {
            panel.hidden = false;
            trigger.setAttribute('aria-expanded', 'true');
            search.value = '';
            filter('');
            search.focus();
        }

        function close() {
            panel.hidden = true;
            trigger.setAttribute('aria-expanded', 'false');
        }

        function filter(query) {
            var q = query.trim().toLowerCase();
            items.forEach(function (li) {
                li.style.display = q === '' || li.textContent.toLowerCase().indexOf(q) !== -1 ? '' : 'none';
            });
        }

        trigger.addEventListener('click', function () {
            panel.hidden ? open() : close();
        });

        search.addEventListener('input', function () {
            filter(search.value);
        });

        search.addEventListener('keydown', function (e) {
            if (e.key === 'Escape') { close(); trigger.focus(); }
        });

        document.addEventListener('click', function (e) {
            if (!control.contains(e.target)) close();
        });
    });
})();
